"use strict";(()=>{const W=1536,H=1024,$=id=>document.getElementById(id),e={opening:$("opening"),enter:$("enter"),sequence:$("sequence"),skip:$("skip"),grid:$("grid"),heartbeat:$("heartbeat"),logo:$("logoStage"),titles:$("titles"),scanner:$("scanner"),loading:$("loading"),hub:$("hub"),canvas:$("hubCanvas"),welcome:$("welcome"),particles:$("particles"),dialog:$("dialog"),dt:$("dialogTitle"),dx:$("dialogText"),da:$("dialogAction")};let running=false,audio=null;const wait=ms=>new Promise(r=>setTimeout(r,ms));function scale(){e.canvas.style.setProperty("--scale",Math.min(innerWidth/W,innerHeight/H))}function particles(){const c=e.particles,x=c.getContext("2d");let p=[];function resize(){c.width=innerWidth;c.height=innerHeight;p=Array.from({length:Math.max(50,Math.round(innerWidth/22))},()=>({x:Math.random()*c.width,y:Math.random()*c.height,r:Math.random()*1.4+.3,s:Math.random()*.18+.04,a:Math.random()*.55+.12}))}function draw(){x.clearRect(0,0,c.width,c.height);p.forEach(q=>{q.y-=q.s;if(q.y<-4){q.y=c.height+4;q.x=Math.random()*c.width}x.beginPath();x.arc(q.x,q.y,q.r,0,Math.PI*2);x.fillStyle=`rgba(96,222,255,${q.a})`;x.fill()});requestAnimationFrame(draw)}resize();draw();addEventListener("resize",resize)}function ctx(){if(!audio){const A=window.AudioContext||window.webkitAudioContext;if(!A)return null;audio=new A}return audio}function beat(offset=0){const a=ctx();if(!a)return;const t=a.currentTime+offset,o=a.createOscillator(),g=a.createGain();o.type="sine";o.frequency.setValueAtTime(58,t);o.frequency.exponentialRampToValueAtTime(38,t+.16);g.gain.setValueAtTime(.0001,t);g.gain.exponentialRampToValueAtTime(.34,t+.025);g.gain.exponentialRampToValueAtTime(.0001,t+.24);o.connect(g);g.connect(a.destination);o.start(t);o.stop(t+.26)}function breathing(){const a=ctx();if(!a)return;const o=a.createOscillator(),g=a.createGain(),t=a.currentTime;o.type="sine";o.frequency.value=74;g.gain.value=.0001;o.connect(g);g.connect(a.destination);o.start();g.gain.exponentialRampToValueAtTime(.025,t+1.4);g.gain.exponentialRampToValueAtTime(.0001,t+3.1);o.stop(t+3.2)}function showHub(){running=false;e.opening.classList.add("hidden");e.hub.classList.remove("hidden");scale();setTimeout(()=>e.welcome.classList.add("visible"),550);setTimeout(()=>e.welcome.classList.remove("visible"),4200)}async function start(){if(running)return;running=true;e.enter.classList.add("hidden");e.sequence.classList.remove("hidden");e.skip.classList.remove("hidden");breathing();await wait(700);e.heartbeat.classList.add("active");beat(0);beat(.55);beat(1.25);await wait(2600);e.heartbeat.classList.remove("active");e.logo.classList.add("visible");e.grid.classList.add("visible");await wait(1300);e.titles.classList.add("visible");await wait(1900);e.logo.classList.remove("visible");e.titles.classList.remove("visible");await wait(700);e.scanner.classList.add("visible");e.loading.classList.add("visible");for(const m of["Initialisation du jumeau numérique…","Synchronisation des modules Atlas…","Construction de l’environnement humain…","Digital Twin prêt."]){e.loading.textContent=m;await wait(900)}await wait(500);showHub()}function open(title,text){e.dt.textContent=title;e.dx.textContent=text;e.dialog.showModal()}function init(){particles();e.enter.addEventListener("click",start);e.skip.addEventListener("click",showHub);addEventListener("resize",scale);document.querySelectorAll(".hot").forEach(h=>h.addEventListener("click",()=>open(h.dataset.title,h.dataset.text)));e.da.addEventListener("click",()=>e.dialog.close());console.info("Atlas Opening Hub 0.9.0 chargé.")}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",init,{once:true}):init()})();
